import { useEffect, useState } from 'react';
import { MapPin, Mail, Github, Linkedin } from 'lucide-react';
import { useApp } from '../context/AppContext';
import t from '../i18n/translations';

const phrasesEn = ['Cybersecurity Enthusiast','AI & Gen AI Practitioner','Web Developer','Network Enthusiast','MIS Student'];
const phrasesAr = ['متحمس للأمن السيبراني','ممارس للذكاء الاصطناعي','مطور ويب','متحمس للشبكات','طالب نظم معلومات'];

export default function Hero() {
  const { dark, lang } = useApp();
  const tr = t[lang];
  const phrases = lang === 'ar' ? phrasesAr : phrasesEn;

  const [text, setText] = useState('');
  const [pi, setPi] = useState(0);
  const [ci, setCi] = useState(0);
  const [del, setDel] = useState(false);

  useEffect(() => { setText(''); setCi(0); setPi(0); setDel(false); }, [lang]);

  useEffect(() => {
    const phrase = phrases[pi];
    const timer = setTimeout(() => {
      if (!del) {
        setText(phrase.slice(0, ci + 1));
        if (ci + 1 === phrase.length) { setTimeout(() => setDel(true), 1600); return; }
        setCi(c => c + 1);
      } else {
        setText(phrase.slice(0, ci - 1));
        if (ci - 1 === 0) { setDel(false); setPi(p => (p + 1) % phrases.length); setCi(0); return; }
        setCi(c => c - 1);
      }
    }, del ? 45 : 90);
    return () => clearTimeout(timer);
  }, [ci, pi, del, phrases]);

  const base = dark ? 'bg-[#0f0f14]' : 'bg-parchment';
  const textMuted = dark ? 'text-white/50' : 'text-muted2';
  const borderBtn = dark ? 'border-white/20 text-white/70 hover:border-amber hover:text-amber' : 'border-ink/20 text-ink2 hover:border-amber hover:text-amber';
  const socBtn = dark ? 'border-white/15 text-white/50 hover:border-amber hover:text-amber' : 'border-ink/12 text-muted2 hover:border-amber hover:text-amber';
  const badgeBg = dark ? 'bg-[#1a1a28]' : 'bg-parchment';
  const textBase = dark ? 'text-white' : 'text-ink';

  return (
    <section id="hero" className={`min-h-screen ${base} grid md:grid-cols-2 items-center gap-8 px-[5%] relative overflow-hidden transition-colors duration-300`}>
      <div className="blob-hero w-[520px] h-[520px] bg-amber opacity-10 top-[-80px] right-[-100px]" />
      <div className="blob-hero-2 w-[240px] h-[240px] bg-teal opacity-[0.07] bottom-[-30px] left-[35%]" />

      <div className="relative z-10 pt-24 pb-10 md:pb-0 md:pt-0">
        <span className="inline-flex items-center gap-1.5 text-xs font-semibold tracking-widest uppercase text-amber mb-4">
          <MapPin size={12} /> Asyut, Egypt
        </span>
        <p className={`text-lg ${textMuted} mb-1`}>{tr.hiIm}</p>
        <h1 className="font-serif-display leading-[1.05] tracking-tight">
          <span className={`block text-5xl md:text-7xl ${textBase}`}>KeMoO</span>
          <em className="block text-5xl md:text-7xl text-amber not-italic font-serif-display">Basem Fathi.</em>
        </h1>
        <div className="flex items-center gap-2 mt-5 text-sm font-medium">
          <span className="text-amber font-bold">→</span>
          <span className={`font-semibold ${textBase}`}>{text}</span>
          <span className="text-amber animate-[ping2_1s_step-end_infinite]">|</span>
        </div>
        <p className={`mt-4 text-[0.95rem] leading-[1.8] ${textMuted} max-w-[440px]`}>{tr.heroDesc}</p>
        <div className="flex gap-3 flex-wrap mt-7">
          <a href="#projects" className="px-6 py-3 bg-amber text-white font-semibold text-sm rounded-full transition-all hover:bg-amber2 hover:-translate-y-1 hover:shadow-[0_8px_24px_rgba(240,165,0,.3)]">{tr.viewWork}</a>
          <a href="#contact" className={`px-6 py-3 border-[1.5px] font-semibold text-sm rounded-full transition-all hover:-translate-y-1 ${borderBtn}`}>{tr.getInTouch}</a>
        </div>
        <div className="flex items-center gap-3 mt-7">
          <span className={`text-xs uppercase tracking-wider ${textMuted}`}>{tr.findMe}</span>
          {[
            { href:'https://www.linkedin.com/in/karem-basem', icon:<Linkedin size={14}/> },
            { href:'https://github.com/Kareem-Basem', icon:<Github size={14}/> },
            { href:'mailto:karemalwy1@gmail.com', icon:<Mail size={14}/> },
          ].map((s,i) => (
            <a key={i} href={s.href} target={s.href.startsWith('http')?'_blank':undefined} rel="noreferrer"
              className={`w-9 h-9 rounded-full border-[1.5px] flex items-center justify-center transition-all hover:-translate-y-0.5 ${socBtn}`}>
              {s.icon}
            </a>
          ))}
        </div>
      </div>

      {/* Right — Real Photo */}
      <div className="hidden md:flex flex-col items-center gap-5 relative z-10">
        <div className="relative w-[300px] h-[300px] float">
          <div className="blob-avatar absolute inset-0 bg-gradient-to-br from-amber to-[#ffd166]" />
          <div className="absolute inset-[22px] rounded-full overflow-hidden shadow-inner">
            <img
              src="/assets/photo/kareem.jpg"
              alt="Kareem Basem Fathi"
              className="w-full h-full object-cover object-top"
              onError={e => {
                e.target.style.display = 'none';
                e.target.nextSibling.style.display = 'flex';
              }}
            />
            <div className={`hidden w-full h-full items-center justify-center ${dark?'bg-[#1a1a28]':'bg-cream2'}`}>
              <span className="font-serif-display text-[4rem] italic text-ink2">KB</span>
            </div>
          </div>
          <div className={`absolute top-4 -right-4 ${badgeBg} rounded-2xl px-3 py-2 shadow-[0_8px_32px_rgba(26,26,46,.15)] flex items-center gap-2`}>
            <span className="w-2 h-2 rounded-full bg-green-500 ping2 block" />
            <div>
              <div className={`text-[0.78rem] font-semibold ${textBase}`}>{tr.openToWork}</div>
              <div className="text-[0.65rem] text-muted">{tr.availableNow}</div>
            </div>
          </div>
          <div className={`absolute bottom-8 -left-6 ${badgeBg} rounded-2xl px-3 py-2 shadow-[0_8px_32px_rgba(26,26,46,.15)] flex items-center gap-2`}>
            <span className="font-serif-display text-2xl italic text-teal">20+</span>
            <div className="text-[0.65rem] text-muted leading-tight">{tr.certifications}<br/>{tr.earned}</div>
          </div>
        </div>
      </div>
    </section>
  );
}
